 20	static void toplevel_list_append(struct gui *g, struct widget *e)
 21	{
 22	  struct widget_list *new;
 23	
 24	  new = calloc(1, sizeof(struct widget_list));
 25	  if (new == NULL) OOM;
 26	
 27	  new->item = e;
 28	
 29	  if (g->toplevel == NULL) {
 30	    g->toplevel = new;
 31	    new->last = new;
 32	    return;
 33	  }
 34	
 35	  g->toplevel->last->next = new;
 36	  g->toplevel->last = new;
 37	}
