 74	/*************************************************************************/
 75	
 76	void widget_add_child_internal(
 77	    gui *_gui, widget *parent, widget *child, int position)
 78	{
 79	  struct widget *p = parent;
 80	  struct widget *c = child;
 81	  struct widget_list *new;
 82	  struct widget_list *prev, *cur;
 83	  int i;
 84	
 85	  new = calloc(1, sizeof(struct widget_list));
 86	  if (new == NULL) OOM;
 87	
 88	  new->item = c;
 89	  c->parent = p;
 90	
 91	  prev = NULL;
 92	  cur = p->children;
 93	
 94	  for (i = 0; position < 0 || i < position; i++) {
 95	    if (cur == NULL) break;
 96	    prev = cur;
 97	    cur = cur->next;
 98	  }
 99	
100	  /* TODO: warn/err if i != position+1? */
101	
102	  if (prev == NULL) {
103	    /* new is at head */
104	    new->next = p->children;
105	    if (p->children != NULL) new->last = p->children->last;
106	    else                     new->last = new;
107	    p->children = new;
108	    goto repack;
109	  }
110	
111	  if (cur == NULL) {
112	    /* new is at tail */
113	    prev->next = new;
114	    p->children->last = new;
115	    goto repack;
116	  }
117	
118	  /* new is between two existing items */
119	  prev->next = new;
120	  new->next = cur;
121	
122	repack:
123	  send_event(_gui, REPACK, p->id);
124	}
125	
126	void widget_del_child_internal(gui *_gui, widget *parent, widget *child)
127	{
128	  struct widget *p = parent;
129	  struct widget *c = child;
130	  struct widget_list *prev, *cur;
131	
132	  c->parent = NULL;
133	
134	  prev = NULL;
135	  cur = p->children;
136	
137	  while (cur != NULL && cur->item != c) {
138	    prev = cur;
139	    cur = cur->next;
140	  }
141	
142	  if (cur == NULL) ERR("child not found\n");
143	
144	  if (prev == NULL) {
145	    /* child is at head */
146	    p->children = cur->next;
147	    if (p->children != NULL) p->children->last = cur->last;
148	    goto done;
149	  }
150	
151	  if (cur->next == NULL) {
152	    /* child is last (and prev is != NULL) */
153	    prev->next = NULL;
154	    p->children->last = prev;
155	    goto done;
156	  }
157	
158	  /* child is between two existing items */
159	  prev->next = cur->next;
160	
